// purchase_order_monitor.js
// Adds alert info banner on Purchase Orders auto-generated by the Inventory Monitor

frappe.ui.form.on("Purchase Order", {
    refresh(frm) {
        // Show banner if this PO was auto-generated by inventory monitor
        if (frm.doc.lim_auto_generated) {
            const alertRef = frm.doc.lim_alert_ref;
            frm.dashboard.add_comment(
                `📦 Auto-generated by Inventory Monitor${alertRef ? ` — Alert: <a href="/app/inventory-alert/${alertRef}">${alertRef}</a>` : ""}`,
                "blue", true
            );
        }

        // "View Inventory Alert" button for auto-gen POs
        if (frm.doc.lim_alert_ref && frm.doc.docstatus === 1) {
            frm.add_custom_button(__("View Inventory Alert"), () => {
                frappe.set_route("Form", "Inventory Alert", frm.doc.lim_alert_ref);
            }, __("Inventory Monitor"));
        }
    },
});
